978	  // ---------- per-frame ----------
979	  function update(dt, t) {
980	    fp.update(dt);
981	
982	    // Level countdown — one clock for the whole run.
983	    if (active && timerRunning && !failed && !reportSent) {
984	      timeLeft = Math.max(0, timeLeft - dt);
985	      updateClock();
986	      if (timeLeft <= 0) failLevel();
987	    }
988	    applyPanicSky();
989	
990	    // Drones fly, work, and head home.
991	    for (let i = 0; i < drones.length; i++) {
992	      const d = drones[i];
993	      const beam = workBeams[i];
994	      if (d.state === "bay") {
995	        d.model.position.y = d.home.y + Math.sin((t + d.bobOff) * 2) * 0.15;
996	        d.model.userData.ring.rotation.z += dt * 1.2;
997	      } else if (d.state === "flying" || d.state === "returning") {
998	        d.t += dt;
999	        const k = Math.min(1, d.t / d.dur);
1000	        const ease = k * k * (3 - 2 * k);
1001	        d.model.position.lerpVectors(d.from, d.to, ease);
1002	        d.model.position.y += Math.sin(k * Math.PI) * 3;   // arc over the island
1003	        d.model.userData.ring.rotation.z += dt * 6;
1004	        if (k >= 1) {
1005	          if (d.state === "flying") d.state = "working";
1006	          else { d.state = "bay"; d.model.position.copy(d.home); }
1007	        }
1008	      } else if (d.state === "working") {
1009	        const s = d.site;
1010	        d.model.position.set(
1011	          s.anchor.position.x + Math.cos(t * 1.4) * 1.2,
1012	          s.anchor.position.y + 6.5 + Math.sin(t * 2.2) * 0.4,
1013	          s.anchor.position.z + Math.sin(t * 1.4) * 1.2
1014	        );
1015	        d.model.userData.ring.rotation.z += dt * 9;
1016	        beam.visible = true;
1017	        beam.position.set(d.model.position.x, d.model.position.y - 3.2, d.model.position.z);
1018	        beam.material.opacity = 0.35 + Math.sin(t * 11) * 0.2;
1019	
1020	        // The actual work happens whether you watch or not.
1021	        if (active && started && !failed) {
1022	          s.workT += dt;
1023	          if (s.workT >= WORK_TIME) {
1024	            sealSite(s);
1025	            beam.visible = false;
1026	            d.state = "returning";
1027	            d.site = null;
1028	            d.from.copy(d.model.position);
1029	            d.to.copy(d.home);
1030	            d.t = 0;
1031	            d.dur = Math.max(1, d.from.distanceTo(d.to) / DRONE_SPEED);
1032	          }
1033	        }
1034	      }
1035	    }
1036	
1037	    // Sites: status beams, warning blinks, seals, and live upgrades.
1038	    for (const s of sites) {
1039	      if (s.state === "broken") {
1040	        s.beam.material.color.setHex(0xff8a5c);
1041	        s.beam.material.opacity = 0.24 + Math.sin(t * 1.6 + s.idx) * 0.08;
1042	        s.beam.visible = true;
1043	        const warn = s.brokenModel.userData.warn;
1044	        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + s.idx) > 0 ? 1.8 : 0.2;
1045	      } else if (s.state === "working") {
1046	        s.beam.material.color.setHex(0x6fe3ff);
1047	        s.beam.material.opacity = 0.4 + Math.sin(t * 6) * 0.18;
1048	        s.beam.visible = true;
1049	      } else if (s.state === "sealed") {
1050	        s.beam.material.color.setHex(0x8fe3ff);
1051	        s.beam.material.opacity = 0.42;
1052	        s.beam.visible = true;
1053	      } else {
1054	        s.beam.visible = false;       // added — the upgrade itself is the landmark
1055	        if (s.meltT > 0) {            // the checkpoint seal melts away
1056	          s.meltT = Math.max(0, s.meltT - dt);
1057	          s.ice.material.opacity = 0.62 * (s.meltT / MELT_DUR);
1058	          if (s.meltT <= 0) s.ice.visible = false;
1059	        }
1060	        // The improvised upgrades live a little.
1061	        const anim = s.upgradeModel.userData.anim;
1062	        if (anim?.type === "ring") {
1063	          anim.ring.rotation.y += dt * 0.8;
1064	          anim.ring.position.y = 3.4 + Math.sin(t * 1.6) * 0.2;
1065	        } else if (anim?.type === "dome") {
1066	          anim.field.rotation.y += dt * 0.25;
1067	          anim.orbit.rotation.z += dt * 0.6;
1068	        } else if (anim?.type === "skid") {
1069	          anim.pad.position.y = 1.6 + Math.sin(t * 1.8) * 0.25;
1070	        }
1071	      }
1072	    }
1073	
1074	    // Proximity: nearest site, and the ship console.
1075	    nearSite = null;
1076	    let nd = Infinity;
1077	    for (const s of sites) {
1078	      const d = Math.hypot(
1079	        camera.position.x - s.anchor.position.x,
1080	        camera.position.z - s.anchor.position.z
1081	      );
1082	      if (d < nd) { nd = d; if (d <= INTERACT_DIST) nearSite = s; }
1083	    }
1084	    nearConsole = Math.hypot(
1085	      camera.position.x - CONSOLE_POS.x, camera.position.z - CONSOLE_POS.z
1086	    ) <= CONSOLE_DIST;
1087	    consoleGlow.intensity = allAdded() && !reportSent ? 8 + Math.sin(t * 4) * 3 : 5;
1088	
1089	    // Terminals open themselves at the right places, like Level 1. After the
1090	    // fifth accept the report prompt is already open in place; if the player
1091	    // wanders off, any ONLINE system (or the bay console) reopens it.
1092	    const atReportSpot = nearConsole || nearSite?.state === "added";
1093	    if (active && started && !failed) {
1094	      if (dismissedSite && nearSite !== dismissedSite) dismissedSite = null;
1095	      if (reportDismissed && !atReportSpot) reportDismissed = false;
1096	      if (!terminalOpen) {
1097	        if (nearSite?.state === "sealed" && nearSite !== dismissedSite) {
1098	          openTerminal("review", nearSite);
1099	        } else if (atReportSpot && allAdded() && !reportSent && !reportDismissed) {
1100	          openTerminal("report", null);
1101	        }
1102	      } else if (termMode === "review" &&
1103	                 (nearSite !== reviewSite || reviewSite.state !== "sealed")) {
1104	        // walked away mid-review (ADD closes it itself)
1105	        if (nearSite !== reviewSite) closeTerminal(false);
1106	      } else if (termMode === "report" && !atReportSpot && !reportSent) {
