@keyframes meter-glow {
  0%, 100% { filter: brightness(1); }
  50% { filter: brightness(1.4); }
}

/* Level countdown clock (top-left, under the PLANETFALL title).
   Shared by Level 1 (#countdown), the Drone Bay (#db-countdown), and the
   shelved Archive level (#l2-countdown). */
#countdown,
#l2-countdown,
#db-countdown {
  position: absolute;
  top: 78px;
  left: 32px;
  display: flex;
  align-items: center;
  gap: 11px;
  padding: 8px 16px;
  background: rgba(6, 11, 22, 0.78);
  border: 1px solid rgba(111, 227, 255, 0.4);
  border-radius: 9px;
  backdrop-filter: blur(8px);
  transition: border-color 0.3s ease, background 0.3s ease;
}

.cd-label {
  font-size: 10.5px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: var(--accent);
  opacity: 0.95;
}

#countdown-time,
#l2-countdown-time,
#db-countdown-time {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 27px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: var(--ink);
  min-width: 66px;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

/* Urgent state — the clock is running low */
#countdown.is-low,
#l2-countdown.is-low,
#db-countdown.is-low {
  border-color: rgba(255, 90, 90, 0.7);
  background: rgba(40, 10, 12, 0.6);
  animation: cd-pulse 1s ease-in-out infinite;
}
#countdown.is-low .cd-label,
#l2-countdown.is-low .cd-label,
#db-countdown.is-low .cd-label { color: #ff7a6b; }
#countdown.is-low #countdown-time,
#l2-countdown.is-low #l2-countdown-time,
#db-countdown.is-low #db-countdown-time { color: #ff8a78; }

@keyframes cd-pulse {
  0%, 100% { box-shadow: 0 0 0 rgba(255, 90, 90, 0); }
  50% { box-shadow: 0 0 18px rgba(255, 90, 90, 0.55); }
}

/* Critical state — under a few seconds, the clock goes frantic */
#countdown.is-critical,
#l2-countdown.is-critical,
#db-countdown.is-critical {
  border-color: rgba(255, 60, 60, 0.95);
  background: rgba(60, 8, 10, 0.72);
  animation: cd-panic 0.5s steps(2, end) infinite;
}
#countdown.is-critical .cd-label,
#l2-countdown.is-critical .cd-label,
#db-countdown.is-critical .cd-label { color: #ff4d4d; }
#countdown.is-critical #countdown-time,
#l2-countdown.is-critical #l2-countdown-time,
#db-countdown.is-critical #db-countdown-time {
  color: #ff5a4d;
  text-shadow: 0 0 12px rgba(255, 70, 60, 0.9);
}

@keyframes cd-panic {
  0% { box-shadow: 0 0 22px rgba(255, 50, 50, 0.8); transform: translateX(-1px); }
  100% { box-shadow: 0 0 8px rgba(255, 50, 50, 0.4); transform: translateX(1px); }
}

/* Time-out fail screen */
/* ---------- landing briefing modal ---------- */
#briefing,
#l2-briefing,
#db-briefing {
  position: absolute;
  inset: 0;
  z-index: 30;
  pointer-events: auto;     /* #ui is pointer-events:none — re-enable for the modal */
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
  background: radial-gradient(ellipse at 50% 30%, rgba(20, 16, 44, 0.62), rgba(2, 4, 10, 0.86));
  backdrop-filter: blur(7px);
  animation: bf-fade 0.5s ease both;
}
#briefing.hidden,
#l2-briefing.hidden,
#db-briefing.hidden { display: none; }

@keyframes bf-fade {
  from { opacity: 0; }
  to { opacity: 1; }
}

.bf-card {
  width: min(540px, 92vw);
  max-height: 88vh;
  overflow-y: auto;
  padding: 30px 34px 26px;
  text-align: left;
  background: var(--panel-bg);
  border: 1px solid rgba(111, 227, 255, 0.28);
  border-radius: 16px;
  box-shadow: 0 26px 80px rgba(2, 4, 10, 0.7), 0 0 50px rgba(111, 227, 255, 0.12);
  animation: bf-rise 0.55s cubic-bezier(0.16, 1, 0.3, 1) both;

