/* ---------- Level 3 HUD ("Launch Clearance") ---------- */

/* The briefing quotes the ship's AI — set the line apart. */
.bf-quote {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 12.5px;
  color: var(--accent);
  border-left: 2px solid rgba(111, 227, 255, 0.45);
  padding-left: 12px;
  margin-top: 10px;
}

/* The launch code — one segment per confirmed answer */
#lc-code {
  position: absolute;
  top: 136px;
  left: 32px;
  padding: 12px 14px;
  background: rgba(6, 11, 22, 0.78);
  border: 1px solid rgba(255, 210, 122, 0.4);
  border-radius: 9px;
  backdrop-filter: blur(8px);
}
.lc-code-head {
  font-size: 10px;
  letter-spacing: 0.22em;
  font-weight: 700;
  color: var(--accent-warm);
  margin-bottom: 9px;
}
#lc-code-segs {
  display: flex;
  gap: 6px;
}
.lc-seg {
  display: inline-grid;
  place-items: center;
  min-width: 44px;
  height: 26px;
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 12px;
  letter-spacing: 0.08em;
  color: var(--ink);
  opacity: 0.4;
  border: 1px dashed rgba(232, 244, 255, 0.35);
  border-radius: 5px;
}
.lc-seg.is-locked {
  opacity: 1;
  color: #1a1206;
  font-weight: 700;
  border: none;
  background: linear-gradient(90deg, #ffd27a, #ffe7b0);
  box-shadow: 0 0 14px rgba(255, 210, 122, 0.5);
}

/* The pre-flight console — the whole level happens here */
#lc-console {
  position: absolute;
  pointer-events: auto;
  bottom: 70px;
  left: 50%;
  transform: translateX(-50%);
  width: min(620px, calc(100vw - 40px));
  padding: 15px 18px;
  background: rgba(4, 10, 18, 0.88);
  border: 1px solid rgba(111, 227, 255, 0.42);
  border-radius: 8px;
  box-shadow: 0 14px 40px rgba(2, 4, 10, 0.55), 0 0 24px rgba(111, 227, 255, 0.12);
  backdrop-filter: blur(6px);
  text-align: left;
}
#lc-console.hidden { display: none; }

#lc-speaker {
  font-size: 10px;
  letter-spacing: 0.22em;
  font-weight: 700;
  color: var(--accent);
  margin-bottom: 7px;
}
#lc-question {
  font-size: 14.5px;
  line-height: 1.5;
  color: var(--ink);
  margin-bottom: 12px;
}

/* The tool menu — pick a way to look it up */
#lc-menu:not(.hidden) {
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.lc-opt {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 7px 10px;
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 13px;
  text-align: left;
  color: var(--ink);
  cursor: pointer;
  background: rgba(111, 227, 255, 0.07);
  border: 1px solid rgba(111, 227, 255, 0.28);
  border-radius: 7px;
  transition: background 0.15s ease, border-color 0.15s ease, transform 0.1s ease;
}
.lc-opt:hover:not(:disabled):not(.is-dead) {
  background: rgba(111, 227, 255, 0.16);
  border-color: rgba(111, 227, 255, 0.55);
  transform: translateY(-1px);
}
.lc-opt kbd {
  display: inline-grid;
  place-items: center;
  min-width: 22px;
  height: 22px;
  font-family: inherit;
  font-size: 12px;
  font-weight: 700;
  color: #04121a;
  background: linear-gradient(90deg, #6fe3ff, #9af0ff);
  border-radius: 5px;
  flex: none;
}
.lc-opt.is-skill { border-color: rgba(255, 210, 122, 0.4); }
.lc-opt.is-skill kbd { background: linear-gradient(90deg, #ffd27a, #ffe7b0); }
.lc-opt.is-dead {
  opacity: 0.38;
  cursor: default;
  text-decoration: line-through;
}
.lc-opt.is-used {
  border-color: rgba(92, 255, 176, 0.5);
  background: rgba(92, 255, 176, 0.08);
}
.lc-opt:disabled { cursor: default; }

/* What the tool printed */
#lc-output:not(.hidden) {
  display: flex;
  flex-direction: column;
  gap: 5px;
  margin-top: 12px;
  padding-top: 10px;
  border-top: 1px solid rgba(111, 227, 255, 0.16);
  max-height: 178px;
  overflow-y: auto;
}
.lc-row {
  display: flex;
  gap: 12px;
  font-size: 12.5px;
  line-height: 1.35;
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
}
.lc-row .lc-k { color: var(--ink); opacity: 0.55; min-width: 96px; flex: none; }
.lc-row .lc-v { color: var(--ink); opacity: 0.85; }
.lc-echo { margin-bottom: 3px; }
.lc-prompt { color: var(--accent); opacity: 0.9; flex: none; }
.lc-cmd { color: var(--ink); }

/* Confirm chips — the answer is on screen; click it */
#lc-answers:not(.hidden) {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 8px;
  margin-top: 12px;
  padding-top: 10px;
  border-top: 1px solid rgba(92, 255, 176, 0.2);
}
.lc-answers-head {
  width: 100%;
  font-size: 10px;
  letter-spacing: 0.22em;
  font-weight: 700;
  color: #7cffb0;
}
.lc-chip {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 7px 12px;
  font-family: inherit;
  font-size: 12.5px;
  font-weight: 600;
  letter-spacing: 0.04em;
  color: var(--ink);
  cursor: pointer;
  background: rgba(92, 255, 176, 0.08);
  border: 1px solid rgba(92, 255, 176, 0.4);
  border-radius: 7px;
  transition: background 0.15s ease, border-color 0.15s ease, transform 0.1s ease;
}
.lc-chip:hover:not(.is-wrong) {
  background: rgba(92, 255, 176, 0.18);
  border-color: rgba(92, 255, 176, 0.7);
  transform: translateY(-1px);
}
.lc-chip kbd {
  display: inline-grid;
  place-items: center;
  min-width: 20px;
  height: 20px;
  font-family: ui-monospace, monospace;
  font-size: 11px;
  font-weight: 700;
  color: #04121a;
  background: linear-gradient(90deg, #5cffb0, #bfffe0);
  border-radius: 4px;
  flex: none;
}
.lc-chip.is-wrong {
  opacity: 0.35;
  cursor: default;
  text-decoration: line-through;
}

/* The finale: one pre-filled command, one Enter */
.lc-single {
  display: flex;
  align-items: center;
  gap: 8px;
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 16px;
  cursor: pointer;
}
.lc-single .lc-cmd { color: var(--ink); }
.lc-single-cta {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 12px;
  cursor: pointer;
}
.lc-cursor {
  display: inline-block;
  width: 8px;
  height: 16px;
  background: var(--accent);
  animation: term-blink 1s steps(1) infinite;
}

/* Confirm / dead-end flashes, same voice as the terminal's */
#lc-msg {
  margin-top: 10px;
  min-height: 16px;
  font-size: 12.5px;
  letter-spacing: 0.02em;
  opacity: 0;
  transition: opacity 0.25s ease;
}
#lc-msg.show-ok { opacity: 0.92; color: #7cffb0; }
#lc-msg.show-err { opacity: 0.92; color: #ff8a73; }

@media (max-width: 680px) {
  #lc-code { top: 124px; left: 16px; padding: 9px 11px; }
  .lc-seg { min-width: 36px; height: 22px; font-size: 10.5px; }
  #lc-console { bottom: 48px; padding: 12px 13px; }
  #lc-question { font-size: 13px; }
  .lc-opt { font-size: 11.5px; }
}
